// ─── PAYMENT GATE HOOK ───────────────────────────────────────────────────────
// Returns: 'none' | 'pending' | 'approved'
const usePaymentStatus = (requiredAmount = 0) => {
  const { payments, currentUser } = useApp();
  if (!currentUser) return 'none';
  const userPayments = payments.filter(p => p.user_id === currentUser.id);
  const approved = userPayments.filter(p => p.status === 'Approved');
  const pending = userPayments.filter(p => p.status === 'Pending');
  const totalApproved = approved.reduce((s, p) => s + Number(p.amount), 0);
  if (totalApproved >= requiredAmount && approved.length > 0) return 'approved';
  if (pending.length > 0) return 'pending';
  return 'none';
};

// ─── PAYMENT GATE BLOCK UI ───────────────────────────────────────────────────
const PaymentGate = ({ requiredAmount, setPage, children }) => {
  const status = usePaymentStatus(requiredAmount);
  if (status === 'approved') return children;
  if (status === 'pending') return (
    <div style={{ background: 'rgba(201,168,76,0.08)', border: '1px solid rgba(201,168,76,0.35)', borderRadius: 14, padding: 28, textAlign: 'center', margin: '16px 0' }}>
      <div style={{ fontSize: 36, marginBottom: 12 }}>⏳</div>
      <div style={{ fontFamily: 'Rajdhani', fontSize: 20, fontWeight: 700, color: 'var(--gold)', marginBottom: 8 }}>Payment Pending Approval</div>
      <div style={{ fontSize: 14, color: 'var(--muted)', marginBottom: 20, lineHeight: 1.7 }}>Your payment receipt has been submitted and is awaiting admin approval. You will be able to invest or order once it is approved.</div>
      <button className="btn btn-secondary btn-sm" onClick={() => setPage('dashboard')}>View Dashboard</button>
    </div>
  );
  return (
    <div style={{ background: 'rgba(227,25,55,0.07)', border: '1px solid rgba(227,25,55,0.3)', borderRadius: 14, padding: 28, textAlign: 'center', margin: '16px 0' }}>
      <div style={{ fontSize: 36, marginBottom: 12 }}>🔒</div>
      <div style={{ fontFamily: 'Rajdhani', fontSize: 20, fontWeight: 700, color: 'var(--red)', marginBottom: 8 }}>Payment Required</div>
      <div style={{ fontSize: 14, color: 'var(--muted)', marginBottom: 20, lineHeight: 1.7 }}>You must make a payment and have it approved by the admin before you can invest or order a car. This protects all parties involved.</div>
      <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
        <button className="btn btn-primary" onClick={() => setPage('invest')}>Make a Payment</button>
        <button className="btn btn-secondary" onClick={() => setPage('dashboard')}>View Dashboard</button>
      </div>
    </div>
  );
};

