// ─── INVEST FROM BALANCE MODAL ───────────────────────────────────────────────
const InvestFromBalanceModal = ({ title, amount, setAmount, minAmount, returnRate, planLabel, onClose, onConfirm }) => {
  const availableBalance = useAvailableBalance();
  const maxAmount = Math.floor(availableBalance / 1000) * 1000 || availableBalance;
  const isInsufficient = amount > availableBalance;
  const isValid = amount >= (minAmount || 1000) && !isInsufficient;

  return (
    <div className="modal-overlay" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal" style={{ maxWidth: 480 }}>
        <button className="modal-close" onClick={onClose}>✕</button>
        <div className="modal-title">{title}</div>

        {/* Balance display */}
        <div style={{ background: 'rgba(0,200,83,0.08)', border: '1px solid rgba(0,200,83,0.25)', borderRadius: 12, padding: 16, marginBottom: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontSize: 12, color: 'var(--muted)', marginBottom: 2 }}>Available Balance</div>
            <div style={{ fontFamily: 'Rajdhani', fontSize: 24, fontWeight: 700, color: 'var(--green)' }}>${availableBalance.toLocaleString()}</div>
          </div>
          <div style={{ fontSize: 28 }}>💰</div>
        </div>

        {/* Amount slider */}
        <div style={{ textAlign: 'center', color: 'var(--muted)', fontSize: 13, marginBottom: 8 }}>Select investment amount</div>
        <div style={{ fontFamily: 'Rajdhani', fontSize: 40, fontWeight: 700, textAlign: 'center', color: isInsufficient ? 'var(--red)' : 'var(--white)', marginBottom: 12 }}>${amount.toLocaleString()}</div>
        <input
          type="range"
          className="range-input"
          min={minAmount || 1000}
          max={Math.max(availableBalance, minAmount || 1000)}
          step={100}
          value={Math.min(amount, availableBalance)}
          onChange={e => setAmount(Number(e.target.value))}
        />
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: 'var(--muted)', marginBottom: 20 }}>
          <span>Min: ${(minAmount || 1000).toLocaleString()}</span>
          <span>Max: ${availableBalance.toLocaleString()}</span>
        </div>

        {/* Insufficient balance warning */}
        {isInsufficient && (
          <div style={{ background: 'rgba(227,25,55,0.1)', border: '1px solid rgba(227,25,55,0.3)', borderRadius: 10, padding: 14, marginBottom: 16, fontSize: 13, color: '#ff9999' }}>
            ⚠ Insufficient balance. You have ${availableBalance.toLocaleString()} available but selected ${amount.toLocaleString()}.
          </div>
        )}

        {/* Return estimate */}
        {!isInsufficient && (
          <div style={{ background: 'rgba(0,200,83,0.08)', border: '1px solid rgba(0,200,83,0.2)', borderRadius: 10, padding: 14, marginBottom: 24, display: 'flex', justifyContent: 'space-between', fontSize: 14 }}>
            <span style={{ color: 'var(--muted)' }}>Estimated Annual Return ({returnRate})</span>
            <span style={{ color: 'var(--green)', fontWeight: 700 }}>+${(amount * parseFloat(returnRate) / 100).toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
          </div>
        )}

        {/* Amount remaining after invest */}
        {!isInsufficient && (
          <div style={{ fontSize: 13, color: 'var(--muted)', textAlign: 'center', marginBottom: 20 }}>
            Remaining balance after investment: <strong style={{ color: 'var(--white)' }}>${(availableBalance - amount).toLocaleString()}</strong>
          </div>
        )}

        <div style={{ display: 'flex', gap: 12 }}>
          <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
          <button
            className="btn btn-primary"
            style={{ flex: 1, opacity: isValid ? 1 : 0.5 }}
            disabled={!isValid}
            onClick={() => isValid && onConfirm(amount)}
          >
            {isInsufficient ? 'Insufficient Balance' : `Invest $${amount.toLocaleString()}`}
          </button>
        </div>
      </div>
    </div>
  );
};

// ─── PAYMENT MODAL (shared) ──────────────────────────────────────────────────
const PaymentModal = ({ title, amount, setAmount, minAmount, returnRate, onClose, onConfirm, planLabel }) => {
  const { addPayment, currentUser } = useApp();
  const [step, setStep] = useState(1); // 1=amount, 2=coin, 3=address, 4=upload
  const [coin, setCoin] = useState('BTC');
  const [receipt, setReceipt] = useState(null);
  const [receiptPreview, setReceiptPreview] = useState(null);
  const [receiptError, setReceiptError] = useState('');
  const [copied, setCopied] = useState(false);

  const wallet = WALLETS[coin];

  const handleFileChange = e => {
    const file = e.target.files[0];
    setReceiptError('');
    if (!file) return;
    if (!['image/jpeg', 'image/png'].includes(file.type)) { setReceiptError('Only JPG or PNG files are accepted.'); return; }
    if (file.size > 5 * 1024 * 1024) { setReceiptError('File must be under 5MB.'); return; }
    setReceipt(file);
    const reader = new FileReader();
    reader.onload = ev => setReceiptPreview(ev.target.result);
    reader.readAsDataURL(file);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(wallet.address).then(() => { setCopied(true); setTimeout(() => setCopied(false), 2000); });
  };

  const handleSubmit = () => {
    if (!receipt) { setReceiptError('Please upload your payment receipt.'); return; }
    addPayment({
      user_id: currentUser.id,
      userName: currentUser.name,
      userEmail: currentUser.email,
      coin,
      amount,
      walletAddress: wallet.address,
      network: wallet.network,
      receiptName: receipt.name,
      receiptPreview,
      plan: planLabel || 'Standard',
      asset: title,
      date: new Date().toISOString().split('T')[0],
      status: 'Pending',
      returnRate,
    });
    onConfirm();
  };

  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${encodeURIComponent(wallet.address)}&bgcolor=161616&color=ffffff&margin=10`;

  return (
    <div className="modal-overlay" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal" style={{ maxWidth: 520 }}>
        <button className="modal-close" onClick={onClose}>✕</button>
        <div className="modal-title">{title}</div>

        {/* Step indicators */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 28 }}>
          {['Amount','Select Coin','Send Payment','Upload Receipt'].map((s, i) => (
            <div key={s} style={{ flex: 1, textAlign: 'center' }}>
              <div style={{ width: 28, height: 28, borderRadius: '50%', background: step > i ? 'var(--green)' : step === i+1 ? 'var(--red)' : 'var(--border)', margin: '0 auto 4px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 700, color: step >= i+1 ? 'white' : 'var(--muted)', transition: 'all 0.3s' }}>{step > i ? '✓' : i+1}</div>
              <div style={{ fontSize: 10, color: step === i+1 ? 'var(--text)' : 'var(--muted)', display: window.innerWidth < 400 ? 'none' : 'block' }}>{s}</div>
            </div>
          ))}
        </div>

        {/* STEP 1 — Amount */}
        {step === 1 && (
          <>
            <div style={{ textAlign: 'center', color: 'var(--muted)', fontSize: 13, marginBottom: 8 }}>Select investment amount (USD)</div>
            <div className="invest-modal-amount">${amount.toLocaleString()}</div>
            <input type="range" className="range-input" min={minAmount || 1000} max={500000} step={1000} value={amount} onChange={e => setAmount(Number(e.target.value))} />
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: 'var(--muted)', marginBottom: 20 }}>
              <span>Min: ${(minAmount || 1000).toLocaleString()}</span><span>Max: $500,000</span>
            </div>
            <div style={{ background: 'rgba(0,200,83,0.08)', border: '1px solid rgba(0,200,83,0.2)', borderRadius: 10, padding: 14, marginBottom: 24, display: 'flex', justifyContent: 'space-between', fontSize: 14 }}>
              <span style={{ color: 'var(--muted)' }}>Estimated Annual Return ({returnRate})</span>
              <span style={{ color: 'var(--green)', fontWeight: 700 }}>+${(amount * parseFloat(returnRate) / 100).toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
            </div>
            <div style={{ display: 'flex', gap: 12 }}>
              <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
              <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => setStep(2)}>Next →</button>
            </div>
          </>
        )}

        {/* STEP 2 — Select Coin */}
        {step === 2 && (
          <>
            <div style={{ color: 'var(--muted)', fontSize: 13, marginBottom: 20, textAlign: 'center' }}>Choose your payment cryptocurrency</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginBottom: 28 }}>
              {Object.entries(WALLETS).map(([key, w]) => (
                <div key={key} onClick={() => setCoin(key)} style={{ display: 'flex', alignItems: 'center', gap: 16, padding: '16px 20px', borderRadius: 12, border: `2px solid ${coin === key ? w.color : 'var(--border)'}`, background: coin === key ? `${w.color}18` : 'rgba(255,255,255,0.02)', cursor: 'pointer', transition: 'all 0.2s' }}>
                  <div style={{ width: 44, height: 44, borderRadius: '50%', background: w.color + '22', border: `1px solid ${w.color}`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20, fontWeight: 700, color: w.color }}>{w.icon}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontFamily: 'Rajdhani', fontSize: 18, fontWeight: 700 }}>{key}</div>
                    <div style={{ fontSize: 12, color: 'var(--muted)' }}>{w.network}</div>
                  </div>
                  <div style={{ width: 20, height: 20, borderRadius: '50%', border: `2px solid ${coin === key ? w.color : 'var(--border)'}`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    {coin === key && <div style={{ width: 10, height: 10, borderRadius: '50%', background: w.color }} />}
                  </div>
                </div>
              ))}
            </div>
            <div style={{ display: 'flex', gap: 12 }}>
              <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setStep(1)}>← Back</button>
              <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => setStep(3)}>Next →</button>
            </div>
          </>
        )}

        {/* STEP 3 — Address & QR */}
        {step === 3 && (
          <>
            <div style={{ textAlign: 'center', marginBottom: 20 }}>
              <div style={{ display: 'inline-flex', alignItems: 'center', gap: 8, padding: '6px 16px', borderRadius: 100, background: wallet.color + '22', border: `1px solid ${wallet.color}`, color: wallet.color, fontSize: 13, fontWeight: 600, marginBottom: 16 }}>{wallet.icon} Send {coin} · {wallet.network}</div>
              <div style={{ fontFamily: 'Rajdhani', fontSize: 28, fontWeight: 700, color: 'var(--red)', marginBottom: 4 }}>Send exactly ${amount.toLocaleString()}</div>
              <div style={{ fontSize: 13, color: 'var(--muted)' }}>worth of {coin} to the address below</div>
            </div>
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 20 }}>
              <div style={{ background: '#161616', border: '1px solid var(--border)', borderRadius: 12, padding: 12 }}>
                <img src={qrUrl} alt="QR Code" width={160} height={160} style={{ display: 'block', borderRadius: 8 }} />
              </div>
            </div>
            <div style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid var(--border)', borderRadius: 10, padding: '12px 16px', marginBottom: 8, display: 'flex', alignItems: 'center', gap: 12 }}>
              <div style={{ flex: 1, fontSize: 12, wordBreak: 'break-all', color: 'var(--text)', fontFamily: 'monospace' }}>{wallet.address}</div>
              <button onClick={handleCopy} style={{ background: copied ? 'var(--green)' : 'var(--red)', color: 'white', border: 'none', borderRadius: 6, padding: '6px 14px', fontSize: 12, fontWeight: 600, cursor: 'pointer', whiteSpace: 'nowrap', transition: 'all 0.2s' }}>{copied ? '✓ Copied' : 'Copy'}</button>
            </div>
            <div style={{ background: 'rgba(227,25,55,0.08)', border: '1px solid rgba(227,25,55,0.25)', borderRadius: 8, padding: 12, fontSize: 12, color: '#ff9999', marginBottom: 24, lineHeight: 1.6 }}>
              ⚠ Send only <strong>{coin}</strong> on the <strong>{wallet.network}</strong>. Sending any other coin or using the wrong network will result in permanent loss of funds.
            </div>
            <div style={{ display: 'flex', gap: 12 }}>
              <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setStep(2)}>← Back</button>
              <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => setStep(4)}>I've Sent Payment →</button>
            </div>
          </>
        )}

        {/* STEP 4 — Upload Receipt */}
        {step === 4 && (
          <>
            <div style={{ textAlign: 'center', color: 'var(--muted)', fontSize: 13, marginBottom: 20 }}>Upload your payment screenshot or transaction receipt</div>
            <div style={{ border: `2px dashed ${receipt ? 'var(--green)' : 'var(--border)'}`, borderRadius: 12, padding: 24, textAlign: 'center', background: receipt ? 'rgba(0,200,83,0.05)' : 'rgba(255,255,255,0.02)', marginBottom: 4 }}>
              {receiptPreview
                ? <img src={receiptPreview} alt="Receipt" style={{ maxHeight: 160, maxWidth: '100%', borderRadius: 8, objectFit: 'contain', marginBottom: 10 }} />
                : <div style={{ fontSize: 36, marginBottom: 10 }}>📎</div>
              }
              {receiptPreview
                ? <div style={{ fontSize: 12, color: 'var(--green)', marginBottom: 10 }}>✓ {receipt?.name}</div>
                : <div style={{ fontSize: 12, color: 'var(--muted)', marginBottom: 12 }}>JPG or PNG · Max 5MB</div>
              }
              <input
                type="file"
                accept="image/jpeg,image/png"
                onChange={handleFileChange}
                style={{ display: 'block', width: '100%', fontSize: 13, color: 'var(--muted)' }}
              />
            </div>
            {receipt && <div style={{ fontSize: 12, color: 'var(--green)', marginBottom: 4 }}>✓ {receipt.name}</div>}
            {receiptError && <div style={{ fontSize: 12, color: '#ff6b6b', marginBottom: 4 }}>{receiptError}</div>}
            <div style={{ background: 'rgba(0,200,83,0.08)', border: '1px solid rgba(0,200,83,0.2)', borderRadius: 10, padding: 14, margin: '16px 0', fontSize: 13 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}><span style={{ color: 'var(--muted)' }}>Amount</span><span style={{ fontWeight: 600 }}>${amount.toLocaleString()}</span></div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}><span style={{ color: 'var(--muted)' }}>Coin</span><span style={{ fontWeight: 600, color: wallet.color }}>{coin}</span></div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}><span style={{ color: 'var(--muted)' }}>Status</span><span className="badge badge-gold">Pending Review</span></div>
            </div>
            <div style={{ display: 'flex', gap: 12 }}>
              <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setStep(3)}>← Back</button>
              <button className="btn btn-success" style={{ flex: 1 }} onClick={handleSubmit}>Submit Payment ✓</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

